// Parse HA sensor data into calendar events
const allStates = $input.first().json;

// Handle both array response and wrapped response
const states = Array.isArray(allStates) ? allStates : (allStates.body || allStates);
if (!Array.isArray(states)) return [];

const sensors = {};
for (const s of states) {
  if (s.entity_id && s.entity_id.includes('librus_')) {
    const parts = s.entity_id.replace('sensor.librus_', '').split('_');
    // Remove student ID (first part)
    parts.shift();
    const key = parts.join('_');
    sensors[key] = s;
  }
}

const events = [];
const today = new Date().toISOString().slice(0, 10);

// 1. HomeWorks (sprawdziany)
const hw = sensors['sprawdziany'];
if (hw && hw.attributes && hw.attributes.items) {
  for (const item of hw.attributes.items) {
    if (!item.date || item.date < today) continue;
    const content = (item.content || '').toLowerCase();
    let type = 'Sprawdzian';
    if (content.includes('kartk') || content.includes('kartkówka')) type = 'Kartkówka';
    const summary = type + ' ' + item.subject;
    const ev = {
      summary: summary,
      description: item.content || '',
      source: 'homework',
      sourceId: 'hw_' + item.id,
      date: item.date,
      allDay: true
    };
    if (item.hour_from && item.hour_from.length >= 5) {
      const hf = item.hour_from.slice(0, 5);
      const ht = (item.hour_to || '').slice(0, 5) || hf;
      ev.startTime = item.date + 'T' + hf + ':00';
      ev.endTime = item.date + 'T' + ht + ':00';
      ev.allDay = false;
    }
    events.push(ev);
  }
}

// 2. SchoolFreeDays
const fd = sensors['dni_wolne'];
if (fd && fd.attributes && fd.attributes.items) {
  for (const item of fd.attributes.items) {
    if (!item.date_from) continue;
    if (item.date_to && item.date_to < today) continue;
    const name = item.name || 'Dzien wolny';
    const endDate = new Date(item.date_to || item.date_from);
    endDate.setDate(endDate.getDate() + 1);
    const endStr = endDate.toISOString().slice(0, 10);
    events.push({
      summary: 'Wolne - ' + name,
      description: name,
      source: 'freeday',
      sourceId: 'fd_' + item.id,
      date: item.date_from,
      dateEnd: endStr,
      allDay: true
    });
  }
}

// 3. Substitutions
const sub = sensors['zastepstwa'];
if (sub && sub.attributes && sub.attributes.items) {
  for (const item of sub.attributes.items) {
    if (!item.date || item.date < today) continue;
    let summary;
    if (item.is_cancelled) {
      summary = 'Odwolana ' + item.org_subject;
    } else if (item.new_subject && item.new_subject !== item.org_subject) {
      summary = 'Zastepstwo ' + item.org_subject + ' -> ' + item.new_subject;
    } else {
      summary = 'Zastepstwo ' + item.org_subject;
    }
    const ev = {
      summary: summary,
      description: item.note || '',
      source: 'substitution',
      sourceId: 'sub_' + item.id,
      date: item.date,
      allDay: true
    };
    if (item.hour_from && item.hour_from.length >= 5) {
      const hf = item.hour_from.slice(0, 5);
      const ht = (item.hour_to || '').slice(0, 5) || hf;
      ev.startTime = item.date + 'T' + hf + ':00';
      ev.endTime = item.date + 'T' + ht + ':00';
      ev.allDay = false;
    }
    events.push(ev);
  }
}

// 4. Conferences
const conf = sensors['zebranie'];
if (conf && conf.attributes) {
  const attrs = conf.attributes;
  for (let i = 1; i <= 20; i++) {
    const key = 'zebranie_' + i;
    if (!attrs[key]) break;
    const parts = attrs[key].split(' - ');
    const date = parts[0] || '';
    const topic = parts.slice(1).join(' - ') || '';
    if (!date || date < today) continue;
    events.push({
      summary: 'Wywiadowka',
      description: topic,
      source: 'conference',
      sourceId: 'conf_' + date,
      date: date,
      allDay: true
    });
  }
}

return events.map(e => ({ json: e }));

// Compare Librus events with existing calendar events
const librusEvents = $('Parsuj dane Librus').all();
const calEvents = $('Kalendarz Tymon - pobierz').all();

const existing = new Set();
for (const ce of calEvents) {
  const e = ce.json;
  const summary = (e.summary || '').toLowerCase().trim();
  let date = '';
  if (e.start) {
    date = e.start.date || (e.start.dateTime || '').slice(0, 10);
  }
  if (date && summary) {
    existing.add(date + '|' + summary);
  }
  // Also match by sourceId tag in description
  const desc = (e.description || '');
  const m = desc.match(/\[librus:(\w+)\]/);
  if (m) existing.add('src:' + m[1]);
}

const newEvents = [];
for (const le of librusEvents) {
  const e = le.json;
  const key = e.date + '|' + e.summary.toLowerCase().trim();
  const srcKey = 'src:' + e.sourceId;
  if (!existing.has(key) && !existing.has(srcKey)) {
    newEvents.push({ json: e });
  }
}

return newEvents.length > 0 ? newEvents : [];
